INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES
('fbf5be28-3881-4622-96e6-08f3bd2ac19c', 'Chronic Absenteeism Reduction', 'Attendance', 'A tiered attendance system pairing early-warning data with relationship-based outreach: prevention for all, personalized nudges and mentoring for students sliding toward chronic absence, and barrier-removal case management for those already there.', 'Attendance Works tiered framework; randomized trials of personalized family outreach (Rogers and Feller, 2018) showing 10 to 15 percent reductions in chronic absence at very low cost; early-warning indicator research showing attendance in the first month predicts year-end chronic absence; mentoring models (Success Mentors) associated with reduced absences in district evaluations.', ARRAY['Reduce chronic absenteeism rate','Improve average daily attendance','Strengthen family-school relationships','Earlier identification of attendance barriers']::text[], 'Full year: systems and messaging in weeks 1 to 6, tiered supports running by month 2, barrier case management ongoing', ARRAY['Weekly attendance data export and early-warning flags','Staff time for outreach and mentoring (1 to 3 hours weekly per mentor)','Family communication tools in home languages','Small budget for recognition and barrier removal (alarm clocks, transit passes)']::text[], '[{"name": "Weekly early-warning data review", "is_core": true, "look_fors": ["Meeting happens weekly on schedule", "Every flagged student gets a named owner", "Response logged within 48 hours"], "description": "Team reviews attendance flags weekly and assigns a response within 48 hours, before absence becomes chronic.", "adaptable_boundaries": ["Meeting day and length", "Which staff attend"]}, {"name": "Positive-first family outreach", "is_core": true, "look_fors": ["Outreach references the specific student, not a form letter tone", "Contact happens before the 10 percent threshold", "Family voice captured in the log"], "description": "First contact about absence is supportive and curious, not punitive; letters and calls use personalized, plain language about days missed.", "adaptable_boundaries": ["Channel (call, text, letter, home visit)", "Language and messenger"]}, {"name": "Relationship mentor for sliding students", "is_core": true, "look_fors": ["Mentor-student pairs documented", "Weekly touchpoint logged", "Student can name their mentor"], "description": "Students at 10 to 19 percent absence get a named adult who greets them, notices absences, and checks in weekly.", "adaptable_boundaries": ["Who mentors (teachers, staff, coaches)", "Check-in format"]}, {"name": "Barrier assessment and case management", "is_core": false, "look_fors": ["Barrier named in the plan", "Concrete removal action taken"], "description": "For chronically absent students, a structured conversation identifies the actual barrier (health, transport, work, belonging) and the team removes what it can.", "adaptable_boundaries": ["Assessment tool", "Community partners used"]}, {"name": "Attendance culture and recognition", "is_core": false, "look_fors": ["Improvement recognized, not only perfection", "Messaging visible to families"], "description": "School-wide messaging that every day matters, with recognition for improved (not just perfect) attendance.", "adaptable_boundaries": ["Recognition form", "Campaign branding"]}]'::jsonb, '{"target_group": "All students for prevention (Tier 1); the approximately [X] percent at 10 to 19 percent absence for mentoring (Tier 2); the [number] chronically absent students for case management (Tier 3). Priority attention to [student groups] with disproportionate absence rates under current practice.", "problem_statement": "Too many of our students are missing enough school to derail their learning, and our response begins after the damage is done. Last year [X] percent of students were chronically absent (missing 10 percent or more of enrolled days), with rates of [X] percent for [student group] versus [X] percent for peers. Attendance in the first month is a strong predictor of year-end chronic absence, yet our current process flags students only after [number] unexcused absences and leads with consequence letters rather than relationships. We lack a tiered system that prevents, notices early, and removes the actual barriers keeping students out.", "lagging_indicators": ["Chronic absenteeism rate, disaggregated by student group", "Average daily attendance", "Percent of Tier 2 students returning to satisfactory attendance", "Family survey: school notices and cares when my child is absent"], "leading_indicators": ["Percent of flagged students contacted within 48 hours", "Weekly mentor touchpoint completion rate", "Family outreach contacts logged per week", "First-month attendance rate versus last year"], "measurement_timeline": ["Weekly early-warning review with logged decisions", "Monthly tier-movement analysis (who improved, who slid)", "Quarterly disproportionality check by student group", "Annual comparison against baseline year"]}'::jsonb),
('92cde9b2-868d-4168-8034-609081db7a5b', 'Intensive Literacy Intervention', 'Intervention', 'High-dosage, small-group or 1:1 intervention focusing on decoding, fluency, and comprehension for students significantly below grade level.', 'Evidence from targeted intervention studies shows accelerated growth when delivered with sufficient intensity and fidelity.', ARRAY['Accelerate reading growth','Close skill gaps','Improve comprehension']::text[], 'Daily 30–45 minute sessions for 12–24 weeks', ARRAY['Intervention materials','Progress monitoring tools','Training & coaching']::text[], '[{"name": "Diagnostic placement", "is_core": true, "description": "Pinpoint skill deficits to target instruction."}, {"name": "High-dosage small group", "is_core": true, "description": "Daily sessions with explicit instruction."}, {"name": "Cumulative review & practice", "is_core": true, "description": "Spiral practice to solidify learning."}, {"name": "Frequent progress monitoring", "is_core": true, "description": "Weekly tracking to adjust instruction."}]'::jsonb, '{"target_group": "The [number] students in grades [range] scoring more than 1.5 standard deviations below benchmark with inadequate response to prior intervention, reviewed to ensure no student group is over- or under-identified.", "problem_statement": "A small group of students remains far below grade level in reading despite receiving core instruction and standard interventions. Currently [number] students in grades [range] score more than 1.5 standard deviations below benchmark, and [X]% of them have shown flat or declining growth across two or more progress-monitoring cycles. These students need a fundamentally more intensive approach: smaller groups, more minutes, more precise diagnosis of skill gaps, and more frequent progress checks than our current intervention block provides.", "lagging_indicators": ["Rate of improvement versus goal line on progress monitoring", "Percent of students meeting intervention exit criteria", "Benchmark composite movement fall to spring", "Reading self-concept (student survey)"], "leading_indicators": ["Intervention sessions delivered versus scheduled (dosage)", "Group size held at or below [3 to 5] students", "Percent of sessions following the diagnostic-prescriptive plan", "Interventionist-classroom teacher communication touchpoints"], "measurement_timeline": ["Weekly progress monitoring with goal-line analysis", "Intervention plan review every 6 to 8 weeks with intensify-or-exit decisions", "Benchmark screening fall, winter, and spring", "Semester case review with families"]}'::jsonb),
('8b62dd48-8964-422d-b7d7-225fb1bb4c57', 'MTSS/RTI Framework', 'Framework', 'Tiered system providing increasing levels of support matched to student need using screening, progress monitoring, and data-based decision making.', 'Strong evidence for improved outcomes when high-quality core instruction, screening, and targeted interventions are implemented with fidelity.', ARRAY['Improve universal screening coverage','Increase responsiveness to interventions','Reduce special education referrals']::text[], 'Establish within a semester; refine continuously through data cycles', ARRAY['Screening tools','Progress monitoring probes','Intervention menu']::text[], '[{"name": "Universal screening", "is_core": true, "description": "At least 3x/year with high coverage."}, {"name": "Tiered intervention menu", "is_core": true, "description": "Evidence-based options matched to need."}, {"name": "Data meetings", "is_core": true, "description": "Regular team review and instructional adjustments."}, {"name": "Progress monitoring", "is_core": true, "description": "Weekly or biweekly measures to track growth."}, {"name": "Check & adjust", "is_core": false, "description": "Fidelity checks and refinements."}]'::jsonb, '{"target_group": "All students through universal screening (Tier 1); the approximately [X]% needing supplemental intervention (Tier 2) and [X]% needing intensive support (Tier 3), identified by shared data rules rather than teacher discretion alone.", "problem_statement": "Students who need more than core instruction are identified late, inconsistently, or not at all, and the support they receive depends more on which teacher they have than on their data. Currently [X]% of students receive some intervention, but entry and exit decisions lack shared criteria, intervention quality varies across grades, and [X]% of special education referrals show no documented intervention history. The result is students waiting to fail rather than receiving timely, layered support matched to need.", "lagging_indicators": ["Median student growth percentile, by tier and student group", "Percent of Tier 2 students returning to Tier 1 within a semester", "Special education referral and qualification rates", "Course failure or retention rates"], "leading_indicators": ["Percent of students screened within the screening window", "Percent of intervention groups meeting as scheduled", "Data-meeting attendance and decision-log completion", "Percent of interventions with progress monitoring at the planned frequency"], "measurement_timeline": ["Universal screening three times per year", "Biweekly progress monitoring for Tier 2, weekly for Tier 3", "Grade-level data meetings every 4 to 6 weeks with documented decisions", "Annual MTSS fidelity self-assessment"]}'::jsonb),
('a631661f-8ea1-4341-baa2-288347ac7ea0', 'New Teacher Induction & Coaching', 'Adult Practice', 'A structured induction system pairing every new teacher with a trained mentor and regular instructional coaching cycles, so early-career teachers build skill and stay, rather than survive and leave.', 'Reviews of induction research (Ingersoll and Strong, 2011) link comprehensive induction to better retention, instruction, and student achievement. Meta-analysis of instructional coaching (Kraft, Blazar, and Hogan, 2018) finds pooled effects of 0.49 SD on instructional practice and 0.18 SD on achievement. Effects depend on dosage and mentor quality: assigned, trained, same-field mentors with protected time outperform informal buddy systems.', ARRAY['Improve new-teacher retention','Accelerate instructional skill in years 1 to 3','Reduce variance in student experience across classrooms','Build internal mentoring capacity']::text[], 'Full year minimum: mentor matching before day 1, coaching cycles from week 3, learning community monthly, formal reviews each semester', ARRAY['Trained mentors with protected time (release periods or stipends)','Coaching cycle time: observation plus debrief every 2 to 3 weeks','Monthly new-teacher learning community time','Administrator time for non-evaluative check-ins']::text[], '[{"name": "Trained, same-field mentor for every new teacher", "is_core": true, "look_fors": ["Match completed before the first student day", "Mentor has documented release time or stipend", "Weekly contact in the first quarter"], "description": "Mentors are selected for skill, trained for the role, matched by subject or grade, and given protected time, not just goodwill.", "adaptable_boundaries": ["Match across buildings when needed", "Stipend versus release structure"]}, {"name": "Observation-feedback coaching cycles", "is_core": true, "look_fors": ["Cycle cadence held all year", "Debrief within 48 hours of observation", "One next move, practiced, not a list of ten"], "description": "Every 2 to 3 weeks: a focused observation against one agreed look-for, then a debrief that names one strength and one next move with rehearsal.", "adaptable_boundaries": ["Who coaches (mentor, instructional coach, peer)", "Observation length and focus areas"]}, {"name": "Non-evaluative status of mentoring", "is_core": true, "look_fors": ["Mentors do not contribute to evaluation ratings", "New teachers raise real struggles in debriefs"], "description": "Mentoring and coaching are firewalled from formal evaluation so new teachers can show real problems safely.", "adaptable_boundaries": ["How the firewall is communicated"]}, {"name": "New-teacher learning community", "is_core": false, "look_fors": ["Sessions are problem-of-practice based, not announcements", "Attendance held by leadership"], "description": "Monthly facilitated sessions where the cohort works on shared problems of practice and builds peer support.", "adaptable_boundaries": ["Topics driven by cohort needs", "Format and timing"]}, {"name": "Leadership check-ins on conditions", "is_core": false, "look_fors": ["Quarterly cadence kept", "At least one named condition improved per semester"], "description": "Administrators meet each new teacher quarterly about workload, support, and belonging, and act on what they hear.", "adaptable_boundaries": ["Format (individual or small group)"]}]'::jsonb, '{"target_group": "All teachers in years 1 to 3, beginning with this year''s [number] new hires. Note which student populations are most exposed to early-career classrooms and whether that exposure is equitable across the school or network.", "problem_statement": "We are losing new teachers faster than we can develop them, and students in their classrooms feel the difference. Over the past [number] years, [X] percent of teachers left within their first three years, and exit conversations cite [top reasons: workload, isolation, behavior support]. Our current induction is a [number]-day orientation and an informal buddy, with no protected mentoring time and no coaching cycle; observation data show wider variance in instructional quality in years 1 to 3 classrooms than in any other group. The students most affected are in [schools or grades with highest new-teacher concentration], which serve [X] percent [student group]. We lack a system that develops new teachers deliberately rather than hoping they survive.", "lagging_indicators": ["New-teacher retention at years 1, 2, and 3", "Observed instructional growth on the agreed framework", "Student outcome trends in years 1 to 3 classrooms", "Exit interview themes year over year"], "leading_indicators": ["Percent of new teachers with a trained, matched mentor by day 1", "Coaching cycles completed versus scheduled", "New-teacher reported support and safety (quarterly pulse)", "Mentor protected-time hours actually used"], "measurement_timeline": ["Quarterly new-teacher pulse survey", "Coaching cycle logs reviewed monthly by the implementation team", "Semester instructional growth review", "Annual retention and exposure-equity analysis"]}'::jsonb),
('1c5e8b01-c1e1-4328-862b-9b60dfde92dc', 'PBIS (Positive Behavioral Interventions and Supports)', 'Behavior', 'A multi-tiered framework emphasizing proactive strategies for defining, teaching, and supporting appropriate student behaviors.', 'Extensive evidence across hundreds of schools showing reductions in office discipline referrals and improvements in climate.', ARRAY['Reduce office discipline referrals','Increase instructional time','Improve school climate']::text[], 'School-wide rollout over 6–12 months with continuous data cycles', ARRAY['Behavior matrix posters','Acknowledgement system','Referral data tracker']::text[], '[{"name": "Behavior expectations matrix", "is_core": true, "description": "Define 3\u20135 positively stated expectations across settings."}, {"name": "Explicit teaching of expectations", "is_core": true, "description": "Direct instruction and practice of expected behaviors."}, {"name": "Acknowledgement system", "is_core": true, "description": "Consistent reinforcement of expected behaviors."}, {"name": "Data-based problem solving", "is_core": true, "description": "Monthly review of ODRs to target supports."}, {"name": "Classroom routines & corrections", "is_core": false, "description": "Active supervision, precorrections, and calm responses."}]'::jsonb, '{"target_group": "All students school-wide (Tier 1), with Tier 2 supports for the approximately [X]% of students with 2 to 5 referrals. Priority attention to [student groups] who are disproportionately referred under current practice.", "problem_statement": "Office discipline referrals (ODRs) are consuming instructional time and disproportionately affecting some student groups. Last year we logged [number] ODRs, averaging [X] per 100 students per month, with referrals concentrated in [settings such as hallways, cafeteria, transitions]. Students lose an estimated [X] minutes of instruction per referral, and our data show [student group] is referred at [X] times the rate of peers. Reactive discipline has not changed the pattern; we lack a school-wide system that teaches and reinforces expected behavior proactively.", "lagging_indicators": ["ODRs per 100 students per month", "Suspension rate, disaggregated by student group", "Instructional minutes recovered (referrals times average minutes)", "Student and staff school-climate survey scores"], "leading_indicators": ["Percent of staff teaching expectations weekly (walkthrough data)", "Acknowledgment-to-correction ratio (target 4:1)", "Percent of students who can state the school expectations", "Staff consistency in minor versus major referral definitions"], "measurement_timeline": ["Monthly ODR review by the implementation team, disaggregated by location, time, and student group", "Quarterly climate survey pulse (students and staff)", "Semester suspension and disproportionality analysis", "Annual full PBIS tiered fidelity inventory"]}'::jsonb),
('fa46924a-599d-4156-91bd-eaa4817b557f', 'Second Step Social-Emotional Learning', 'SEL', 'A structured SEL curriculum building self-management, relationship skills, and responsible decision-making.', 'Multiple randomized trials report improvements in prosocial behavior and reductions in problem behavior.', ARRAY['Increase prosocial behaviors','Improve self-regulation','Reduce disruptive incidents']::text[], 'Weekly lessons over 20–30 weeks with embedded practice', ARRAY['Lesson kits','Family engagement letters','Implementation guide']::text[], '[{"name": "Weekly explicit SEL lessons", "is_core": true, "description": "Scripted lessons with modeling and practice."}, {"name": "Embedded practice routines", "is_core": true, "description": "Daily prompts to generalize skills."}, {"name": "Reinforcement & reflection", "is_core": true, "description": "Acknowledge use of SEL skills; student reflection."}, {"name": "Family connection", "is_core": false, "description": "Send home practice activities."}]'::jsonb, '{"target_group": "All students in grades [range] receive core SEL lessons (Tier 1); students flagged by counselor referral or climate data receive small-group reinforcement. Attend to whether [student groups] access supports proportionally.", "problem_statement": "Students need stronger skills in self-regulation, problem solving, and peer relationships than our current approach builds. Behavior data show [number] peer-conflict incidents last [term], counselor referrals for emotional regulation have risen [X]% since [year], and on our climate survey only [X]% of students agreed that students at this school help each other. Teachers report losing instructional time to low-level conflict and dysregulation, and our SEL instruction is currently left to individual teacher initiative rather than a consistent, evidence-based curriculum.", "lagging_indicators": ["Peer-conflict incident rate", "Counselor referrals for regulation support", "Climate survey items on belonging and peer support", "Classroom instructional time lost to behavior (teacher estimate)"], "leading_indicators": ["Percent of classrooms delivering the weekly lesson as scheduled", "Student use of taught vocabulary and strategies (observation)", "Teacher-reported integration of skills outside lesson time", "Family awareness of monthly SEL focus (newsletter engagement)"], "measurement_timeline": ["Weekly lesson-completion tracking by grade", "Monthly incident-data review by the implementation team", "Climate survey fall and spring", "Semester review of counselor referral patterns"]}'::jsonb),
('7b50257a-cd7b-4bef-a310-e247298fa83b', 'Structured Literacy Program', 'Literacy', 'Systematic, explicit instruction in phonemic awareness, phonics, fluency, vocabulary, and comprehension aligned to the science of reading.', 'Strong evidence from meta-analyses (e.g., National Reading Panel, IES WWC) showing improved early decoding and long-term reading outcomes.', ARRAY['Improve decoding accuracy','Increase reading fluency','Boost comprehension on grade-level texts']::text[], 'Core implementation over 12–24 weeks with ongoing progress monitoring', ARRAY['Tiered materials set','Decodable texts','Screeners & progress monitors']::text[], '[{"name": "Explicit phonics routines", "is_core": true, "description": "Daily, systematic instruction of sound-spelling patterns with cumulative review."}, {"name": "Phonemic awareness practice", "is_core": true, "description": "Oral blending, segmenting, and manipulation activities."}, {"name": "Decodable text practice", "is_core": true, "description": "Controlled texts aligned to taught patterns for fluency."}, {"name": "Error correction routine", "is_core": true, "description": "Immediate corrective feedback with guided practice."}, {"name": "Vocabulary and background", "is_core": false, "description": "Pre-teach key vocabulary and build knowledge."}]'::jsonb, '{"target_group": "All K-2 students for core instruction (Tier 1), with priority intervention for the [number] students below benchmark on universal screening, disaggregated to ensure [student groups] are progressing proportionally.", "problem_statement": "Our youngest readers are not building the decoding and fluency foundation that later comprehension depends on. On the [fall/winter] universal screening, [X]% of K-2 students scored below benchmark in decoding and [X]% in oral reading fluency, against a district expectation of at least 80% at benchmark. The gap is widest for [student group], at [X]% below benchmark versus [X]% for peers. Our current core materials emphasize exposure over explicit, systematic instruction in phonemic awareness and phonics, and teachers report uneven preparation to deliver structured literacy practices.", "lagging_indicators": ["Universal screening composite (DIBELS, Acadience, or district measure)", "Percent at benchmark in decoding, by grade and student group", "Oral reading fluency growth (words correct per minute)", "Percent of intervention students closing to benchmark"], "leading_indicators": ["Percent of literacy blocks following the structured routine (walkthroughs)", "Teacher confidence in explicit phonics instruction (self-report)", "Student engagement during word work (observation)", "Weekly progress-monitoring completion rate"], "measurement_timeline": ["Weekly progress monitoring for intervention students", "Monthly grade-level data meetings on routine fidelity and student response", "Benchmark screening fall, winter, and spring", "Semester disproportionality check across student groups"]}'::jsonb),
('0c20ba67-f890-4777-a5b2-0210545c4b1a', 'Targeted Math Intervention', 'Math', 'Systematic small-group math intervention built on explicit instruction, visual representations, number-line work, and word-problem schema instruction, with weekly progress monitoring and intensify-or-exit decisions.', 'IES What Works Clearinghouse practice guide, Assisting Students Struggling with Mathematics (2021): strong evidence for systematic instruction, mathematical language, and number lines; moderate to strong evidence for visual representations and timed fluency-building activities. Schema-based instruction trials in the middle grades show moderate to large effects on word-problem solving, including for students with disabilities.', ARRAY['Accelerate growth for students below benchmark in math','Close the word-problem performance gap','Build computational fluency and number sense','Reduce math anxiety through structured success']::text[], 'Semester cycles: diagnostic and grouping in weeks 1 to 2, daily or near-daily 25 to 30 minute sessions, formal review every 6 to 8 weeks', ARRAY['Protected intervention block (25 to 30 minutes, 4 to 5 days weekly)','Trained interventionist or teacher per group of 3 to 5','Diagnostic and progress-monitoring measures','Manipulatives, number lines, and visual representation materials']::text[], '[{"name": "Explicit, systematic intervention lessons", "is_core": true, "look_fors": ["Teacher models with visible reasoning", "Students practice with feedback the same session", "Lesson follows the planned sequence"], "description": "Every session follows a clear sequence: review, modeling with think-aloud, guided practice, independent practice with immediate feedback.", "adaptable_boundaries": ["Curriculum or program used", "Session time of day"]}, {"name": "Visual representations and number lines", "is_core": true, "look_fors": ["Number line visible and used by students", "Students draw or build before writing equations"], "description": "Concrete and visual models (number lines especially) precede and accompany abstract notation in every new concept.", "adaptable_boundaries": ["Specific manipulatives", "Digital versus physical tools"]}, {"name": "Word-problem schema instruction", "is_core": true, "look_fors": ["Students name the problem type", "Representation drawn before solving", "Math vocabulary used in discussion"], "description": "Students learn to identify problem types and represent their structure before computing, with sentence frames supporting mathematical language.", "adaptable_boundaries": ["Problem contexts adjusted to student interests", "Pacing of new schemas"]}, {"name": "Brief timed fluency building", "is_core": false, "look_fors": ["Daily and brief, not occasional and long", "Students chart their own growth"], "description": "5 minutes per session of motivating, timed practice on previously taught skills, tracking personal growth rather than peer comparison.", "adaptable_boundaries": ["Practice format (games, apps, paper)", "Skills targeted"]}, {"name": "Weekly progress monitoring with decision rules", "is_core": true, "look_fors": ["Data plotted weekly", "Decision rule applied, not just data collected"], "description": "Brief weekly measures plotted against a goal line; 4 data points below the line trigger an intensification decision.", "adaptable_boundaries": ["Measure used", "Meeting where decisions happen"]}]'::jsonb, '{"target_group": "The [number] students in grades [range] scoring below the [percentile] on benchmark or showing flat growth across two progress-monitoring cycles, grouped 3 to 5 per interventionist. Review identification to ensure [student groups] are neither over- nor under-represented relative to need.", "problem_statement": "A persistent group of students is falling further behind in mathematics each year, and our current support is not intensive enough to change their trajectory. On the [fall/winter] benchmark, [X] percent of students in grades [range] scored below benchmark, and item analysis shows word problems and number sense as the weakest strands ([X] percent correct versus [X] percent on computation). The gap for [student group] is [X] points and has widened since [year]. Our intervention block currently offers homework help rather than systematic instruction, and no student has exited intervention through documented progress in the past [time period].", "lagging_indicators": ["Rate of improvement versus goal line", "Percent of students meeting exit criteria each cycle", "Benchmark movement fall to spring, by student group", "Word-problem strand performance"], "leading_indicators": ["Intervention dosage: sessions delivered versus scheduled", "Fidelity to the explicit lesson sequence (observation)", "Student use of representations before computation", "Weekly progress-monitoring completion"], "measurement_timeline": ["Weekly progress monitoring plotted against goal lines", "Review every 6 to 8 weeks with intensify, continue, or exit decisions", "Benchmark screening fall, winter, and spring", "Semester disproportionality and exit-rate analysis"]}'::jsonb)
